-- ============================================================
-- CBE Statement Backfill — pre-01 Dec 2025 (spec: scripts/backfill-cbe-2025h2-transfers.ts)
--
-- The live `transfers` table only covered the CBE statement from
-- 01 Dec 2025 onward (013_cbe_statement_import.sql, CBE-IMPORT-SENTINEL).
-- A companion script (scripts/backfill-cbe-2025h2-transfers.ts) was
-- written to backfill everything before that cutoff from Airtable base
-- apphyWTS8wt69LgMI ("Imported table", tblLXt3MvX7ZQHGk6), and migration
-- 106 (opening_balances) already inserts a bank_balance_anchors row for
-- CBE that references a transfer coded 'CBE-CR-2025-001-2025-07-07' —
-- but no migration ever actually created that transfer, because the
-- script requires a SUPABASE_SERVICE_ROLE_KEY + AIRTABLE_API_KEY run
-- from a human's own terminal (deliberately, per its own docstring, to
-- avoid a service-role key ever being pasted into a chat/agent
-- session) and it was never run. So migration 106's INSERT ... SELECT
-- ... FROM transfers WHERE transfer_id_code = 'CBE-CR-2025-001-2025-07-07'
-- matched zero rows and silently inserted nothing — bank_balance_anchors
-- has stayed empty for CBE, and v_account_balances has been computing
-- an all-time sum with no opening-balance correction ever since.
--
-- This migration supplies that missing data directly — fetched for
-- real from the same Airtable base/table via the Airtable MCP connector
-- (not the script, so no service-role key was ever needed), using the
-- exact same transform the script specifies: parse "Post Date" (DD MON
-- YY), require exactly one of Debit/Credit populated, skip any row
-- dated on/after 2025-12-01 (already-live import's territory).
--
-- Every one of the 736 relevant rows carries the bank's own running
-- Balance column. Before writing a single row here, that column's
-- arithmetic was replayed end-to-end: starting from the earliest row
-- (2025-07-07, the anchor) through the latest (2025-11-29), each row's
-- reported balance was confirmed to equal the prior row's balance plus
-- its own signed amount — including reconstructing the true intra-day
-- order wherever multiple rows shared a Post Date (that order isn't
-- recoverable from Post Date alone, only from this arithmetic). The
-- chain held with zero breaks across all 736 rows, which is why this
-- data is trusted enough to seed real financial history.
--
-- 167 of the 653 debit rows are deliberately EXCLUDED from the
-- transfers inserted below: 014_populate_expense_bank_refs.sql already
-- matched these exact FT-references to specific expenses and flipped
-- them to payment_status = true, account_id = CBE — i.e. they're
-- already counted via expenses_out in v_account_balances. Inserting
-- them again here as transfers would double-count that outflow.
-- Excluded by comparing each debit's reference (minus its "\XXX"
-- suffix, which migration 014's bank_ref values never carry) against
-- every bank_ref migration 014 sets for the CBE account. The remaining
-- 486 debits + all 83 credits are genuinely not represented anywhere
-- else in the app and are inserted as ordinary transfers, exactly like
-- migration 013 does for the Dec 2025+ range.
--
-- Idempotent the same way as 013: everything below is wrapped in one
-- DO block guarded by this batch's own sentinel
-- (CBE-IMPORT-SENTINEL-2025H2, matching the script's own constant), so
-- this can be safely re-applied without duplicating data.
-- ============================================================

SET search_path TO public;

DO $$ BEGIN

IF EXISTS (
  SELECT 1 FROM public.transfers WHERE transfer_id_code = 'CBE-IMPORT-SENTINEL-2025H2'
) THEN
  RAISE NOTICE 'CBE 2025H2 backfill already imported — skipping.';
  RETURN;
END IF;

-- ── CREDITS (83 rows, 2025-07-07 .. 2025-11-29) ─────────────────────────────



-- ── DEBITS (486 of 653 rows — 167 already represented via expenses_out,
--    see header) ──────────────────────────────────────────────────────────













-- ── Sentinel (prevents double-import) ───────────────────────────────────────
VALUES (
  'CBE-IMPORT-SENTINEL-2025H2', '2025-11-29', NULL, NULL, 0,
  'Import sentinel — CBE account 1000504664272, backfill batch covering 2025-07-07 to 2025-11-29 (precedes the existing 01 Dec 2025-24 Jun 2026 import, see CBE-IMPORT-SENTINEL). Reconciliation anchor: bank-reported balance 66717.56 as of 2025-07-07, immediately after ref FT25188XDGM2\MEX (see bank_balance_anchors row below).'
);

END $$;

-- ── Reconciliation anchor (migration 106 tried this and silently
--    no-opped since the transfer above didn't exist yet; it exists now) ────
SELECT
  '890c3473-dc57-4c01-9f39-17518047c463',
  '2025-07-07',
  66717.56,
  'CBE statement (Airtable base apphyWTS8wt69LgMI, "Imported table"), Post Date 07 JUL 25 — bank-reported running balance immediately after this transaction. Confirmed as the true earliest transaction (not just earliest by date) by replaying the Balance column''s own arithmetic across all 736 backfilled rows end-to-end with zero breaks.',
  t.id
FROM transfers t
WHERE t.transfer_id_code = 'CBE-CR-2025-001-2025-07-07'
  AND NOT EXISTS (SELECT 1 FROM bank_balance_anchors WHERE account_id = '890c3473-dc57-4c01-9f39-17518047c463' AND as_of_date = '2025-07-07');

-- Verify
SELECT count(*) AS cbe_2025h2_rows FROM transfers WHERE transfer_id_code LIKE 'CBE-%R-2025-%';
SELECT * FROM bank_balance_anchors WHERE account_id = '890c3473-dc57-4c01-9f39-17518047c463';
